const response = $input.first().json;
const text = response.content[0].text;

// Extraer JSON del response
const jsonMatch = text.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('No se encontró JSON en la respuesta de Claude');
}

const calendario = JSON.parse(jsonMatch[0]);
const rows = [];

for (const dia of calendario.dias) {
  rows.push({
    semana: calendario.semana,
    dia: dia.dia,
    fecha: dia.fecha,
    // Instagram
    ig_caption: dia.instagram?.caption || '',
    ig_hashtags: dia.instagram?.hashtags || '',
    ig_tipo: dia.instagram?.tipo || 'feed',
    ig_estado: 'pendiente',
    // Facebook
    fb_caption: dia.facebook?.caption || '',
    fb_estado: 'pendiente',
    // TikTok
    tk_caption: dia.tiktok?.caption || '',
    tk_video_idea: dia.tiktok?.video_idea || '',
    tk_estado: 'pendiente',
    // Meta
    generado_at: new Date().toISOString(),
    aprobado: false
  });
}

return rows.map(r => ({ json: r }));
